int maxPuntuacion(int N, int duracionCara1, int duracionCara2, vector<pair<int, int>> canciones) {
    // Inicializar variables para la mejor puntuación
    int mejorPuntuacion = 0;
    // Función recursiva para explorar combinaciones
    function<void(int, int, int, int)> backtrack = [&](int index, int duracionRestante1, int duracionRestante2, int puntuacionActual) {
        if (index == N) {
            // Actualizar mejor puntuación si es necesario
            mejorPuntuacion = max(mejorPuntuacion, puntuacionActual);
            return;
        }
        // Opción 1: No incluir la canción actual
        backtrack(index + 1, duracionRestante1, duracionRestante2, puntuacionActual);
        // Opción 2: Incluir la canción en la cara 1 si cabe
        if (canciones[index].first <= duracionRestante1) {
            backtrack(index + 1, duracionRestante1 - canciones[index].first, duracionRestante2, puntuacionActual + canciones[index].second);
        }
        // Opción 3: Incluir la canción en la cara 2 si cabe
        if (canciones[index].first <= duracionRestante2) {
            backtrack(index + 1, duracionRestante1, duracionRestante2 - canciones[index].first, puntuacionActual + canciones[index].second);
        }
    };
    // Iniciar backtracking desde el primer índice
    backtrack(0, duracionCara1, duracionCara2, 0);
    return mejorPuntuacion;
}
